// Classic counter — private state via closure
function counter() {
  let count = 0; // Closed over by both methods
  return {
    increment: () => ++count,
    decrement: () => --count,
    getCount: () => count
  };
}
const c = counter();
c.increment(); c.increment();
console.log(c.getCount()); // 2
// count cannot be accessed from outside

// Classic closure bug:
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0); // 3, 3, 3
}
// Fix with let:
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0); // 0, 1, 2
}

