// Common mistake — forgetting to RETURN inside .then():
fetch('/api/user')
  .then(res => {
    res.json(); // Bug! Not returned — next .then gets undefined
  })
  .then(user => console.log(user)); // undefined

// Fix:
  .then(res => res.json()) // Implicit return

async function loadUserData(id) {
  try {
    const res = await fetch(`/api/user/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const user = await res.json();
    return user;
  } catch (err) {
    console.error('Failed:', err);
    throw err; // Re-throw so caller can handle
  }
}

// MISTAKE: Sequential when should be parallel
async function bad() {
  const a = await fetch('/api/a'); // Waits 1s
  const b = await fetch('/api/b'); // Waits another 1s
}

// FIX: Parallel
async function good() {
  const [a, b] = await Promise.all([
    fetch('/api/a'), fetch('/api/b') // Both start at same time
  ]);
}

// Module pattern using closures
const userService = (() => {
  let _users = []; // Private — only accessible via methods
  let _nextId = 1;

  return {
    add(name) {
      const user = { id: _nextId++, name };
      _users.push(user);
      return user;
    },
    getAll() { return [..._users]; }, // Return copy, not reference
    remove(id) { _users = _users.filter(u => u.id !== id); }
  };
})();

userService.add('Abhishek'); // { id: 1, name: 'Abhishek' }
console.log(userService.getAll()); // [{ id: 1, name: 'Abhishek' }]

function debounce(fn, delay) {
  let timerId; // Closed over by returned function
  return function(...args) {
    clearTimeout(timerId); // Cancel previous timer
    timerId = setTimeout(() => {
      fn.apply(this, args); // Call with correct this + args
    }, delay);
  };
}

// React usage with useCallback for stable reference:
const handleSearch = useCallback(
  debounce((query) => {
    if (!query.trim()) return;
    fetchResults(query);
  }, 300),
  [] // Create once
);
// Cleanup: call handleSearch.cancel() on unmount

function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log('Cache hit!');
      return cache.get(key);
    }
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const expensiveFib = memoize(function fib(n) {
  if (n <= 1) return n;
  return expensiveFib(n - 1) + expensiveFib(n - 2);
});

console.log(expensiveFib(40)); // Computed once
console.log(expensiveFib(40)); // Cache hit — instant

// Object.create for explicit prototype setting
const animal = {
  type: 'Animal',
  describe() { return `I am a ${this.type}`; }
};

const dog = Object.create(animal);
dog.type = 'Dog'; // Own property shadows prototype
dog.bark = function() { return 'Woof!'; };

console.log(dog.describe()); // 'I am a Dog' — found on dog (own)
console.log(dog.bark()); // 'Woof!' — own property
console.log(dog.hasOwnProperty('type')); // true — own
console.log(dog.hasOwnProperty('describe')); // false — on prototype

// Prototype chain: dog → animal → Object.prototype → null

