// Content-Security-Policy: default-src 'self'; script-src 'self' 'nonce-randomvalue'

// 1. Code splitting with dynamic import
const Dashboard = React.lazy(() => import('./Dashboard'));

// 2. Avoid layout thrashing
const width = container.offsetWidth; // Read once
elements.forEach(el => {
  el.style.width = width + 'px'; // Write in batch
});

// 3. Passive event listeners for scroll (no preventDefault)
document.addEventListener('scroll', handler, { passive: true });

// 4. RequestAnimationFrame for visual updates
const animate = () => {
  el.style.transform = `translateX(${getPosition()}px)`;
  requestAnimationFrame(animate);
};
